#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int mn = INT_MAX, mx = INT_MIN;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x < mn) mn = x;
            if (x > mx) mx = x;
        }
        printf("%d\n", mx - mn);
    }
    return 0;
}

