#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        mn = 10**9
        mx = -10**9
        for _ in range(N):
            x = int(next(it))
            if x < mn:
                mn = x
            if x > mx:
                mx = x
        out_lines.append(str(mx - mn))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

